const fs = require\('fs'\);
let c = fs.readFileSync\('C:/Projects/VSCode/MitevaLaw/src/messages/bg.json', 'utf8'\);

// Replace specific patterns where « is followed eventually by an ASCII \\" that's NOT closing the JSON string
// These are all the quoted Bulgarian names that need closing »
const fixes = [
  ['«Административноправни науки\\"', '«Административноправни науки»'],
  ['«Св. Климент Охридски\\"', '«Св. Климент Охридски»'],
  ['«Дискриминацията в международното данъчно право\\"', '«Дискриминацията в международното данъчно право»'],
  ['«Райчинова и партньори\\"', '«Райчинова и партньори»'],
];

for \(const [from, to] of fixes\) {
  c = c.split\(from\).join\(to\);
}

fs.writeFileSync\('C:/Projects/VSCode/MitevaLaw/src/messages/bg.json', c, 'utf8'\);

// Validate
try { JSON.parse\(c\); console.log\('Valid JSON'\); } catch\(e\) { console.log\('Error:', e.message\); }
")

